    path.join(path.dirname(htmlPath), '..', 'themes', `${colorMode}.css`),
    htmlPath.replace('.html', `.${colorMode}.css`)
  ];
  for (const p of candidates) {
    try { return await fs.readFile(p, 'utf-8'); } catch { /* next */ }
  }
  return null;
}

